select count(*) from postgres.comments as c, postgres.posts as p, postgres.postlinks as pl, postgres.votes as v, postgres.badges as b, postgres.users as u where u.id = p.owneruserid and p.id = pl.relatedpostid and p.id = v.postid and p.id = c.postid and u.id = b.userid and p.score>=-1 and p.score<=14 and pl.creationdate<=timestamp '2014-06-25 13:05:06' and v.creationdate>=timestamp '2009-02-02 00:00:00' and b."date">=timestamp '2010-08-04 08:50:31' and b."date"<=timestamp '2014-09-02 02:51:22' and u.downvotes>=0;
